let raw = msg.payload;
if (Buffer.isBuffer(raw)) raw = raw.toString('utf8');
if (typeof raw !== 'string') {
    node.warn('Payload string degil');
    return null;
}

const line = raw.trim();
if (!line) return null;

function readNumber(text, key, fallback = 0) {
    const match = text.match(new RegExp('\\|' + key + ':(.*?)(?=\\||$)'));
    if (!match) return fallback;
    const normalized = match[1].trim().replace(',', '.');
    const value = Number(normalized);
    return Number.isFinite(value) ? value : fallback;
}

function readText(text, key, fallback = '') {
    const match = text.match(new RegExp('\\|' + key + ':(.*?)(?=\\||$)'));
    return match ? match[1].trim() : fallback;
}

function fixed(value) {
    return Number(value || 0).toFixed(1);
}

function stamp(date) {
    const pad = (n) => String(n).padStart(2, '0');
    return pad(date.getHours()) + ':' + pad(date.getMinutes()) + ':' + pad(date.getSeconds());
}

let faultState = context.get('faultState') || {
    reason: 'Bilinmiyor',
    status: 'BITTI',
    startedAt: null
};

if (/\|Tablet\|Ar[^|]{0,2}za\|/i.test(line) || line.includes('|Tablet|Ariza|')) {
    faultState = {
        reason: readText(line, 'NEDEN', 'Bilinmiyor'),
        status: readText(line, 'DURUM', 'Yok'),
        startedAt: Date.now()
    };
    context.set('faultState', faultState);
    return null;
}

if (!line.includes('|Tablet|OEE|')) {
    return null;
}

const availability = readNumber(line, 'KULL') * 100;
const performance = readNumber(line, 'PERF') * 100;
const quality = readNumber(line, 'KALITE') * 100;
const oee = readNumber(line, 'OEE') * 100;

const counts = {
    yellow: {
        name: 'Sari',
        key: 'yellow',
        good: readNumber(line, 'SARI_S'),
        scrap: readNumber(line, 'SARI_H'),
        rework: readNumber(line, 'SARI_R')
    },
    blue: {
        name: 'Mavi',
        key: 'blue',
        good: readNumber(line, 'MAVI_S'),
        scrap: readNumber(line, 'MAVI_H'),
        rework: readNumber(line, 'MAVI_R')
    },
    red: {
        name: 'Kirmizi',
        key: 'red',
        good: readNumber(line, 'KIRMIZI_S'),
        scrap: readNumber(line, 'KIRMIZI_H'),
        rework: readNumber(line, 'KIRMIZI_R')
    }
};

Object.keys(counts).forEach((key) => {
    const item = counts[key];
    item.total = item.good + item.scrap + item.rework;
    item.loss = item.scrap + item.rework;
    item.lossRate = item.total > 0 ? (item.loss / item.total) * 100 : 0;
    item.qualityRate = item.total > 0 ? (item.good / item.total) * 100 : 0;
});

const totalProduct = counts.yellow.total + counts.blue.total + counts.red.total;
const goodProduct = counts.yellow.good + counts.blue.good + counts.red.good;
const scrapTotal = counts.yellow.scrap + counts.blue.scrap + counts.red.scrap;
const reworkTotal = counts.yellow.rework + counts.blue.rework + counts.red.rework;
const totalLoss = scrapTotal + reworkTotal;
const errorRate = totalProduct > 0 ? (totalLoss / totalProduct) * 100 : 0;

faultState = context.get('faultState') || faultState;
const stopStatus = String(faultState.status || '').toUpperCase();
const isStopped = stopStatus && !['BITTI', 'YOK', '0', 'OK', 'NORMAL'].includes(stopStatus);
const lineState = isStopped ? 'Durusta' : 'Calisiyor';
const stateSummary = isStopped
    ? (faultState.reason || 'Plansiz durus aktif')
    : 'Hat akisi normal ve veri aliniyor';

const colorCards = Object.keys(counts).map((key) => {
    const item = counts[key];
    const mixRate = totalProduct > 0 ? (item.total / totalProduct) * 100 : 0;
    return {
        key: item.key,
        name: item.name,
        total: item.total,
        good: item.good,
        scrap: item.scrap,
        rework: item.rework,
        lossRate: fixed(item.lossRate),
        qualityRate: fixed(item.qualityRate),
        mixRate: fixed(mixRate)
    };
}).sort((a, b) => b.total - a.total);

const biggestLossColor = colorCards.slice().sort((a, b) => Number(b.lossRate) - Number(a.lossRate))[0] || { name: '-' };
const bestQualityColor = colorCards.slice().sort((a, b) => Number(b.qualityRate) - Number(a.qualityRate))[0] || { name: '-' };

let history = flow.get('oeeHistory') || [];
const now = new Date();
history.push({
    time: stamp(now),
    oee: Number(fixed(oee)),
    quality: Number(fixed(quality)),
    performance: Number(fixed(performance)),
    availability: Number(fixed(availability)),
    error: Number(fixed(errorRate))
});
if (history.length > 10) {
    history = history.slice(history.length - 10);
}
flow.set('oeeHistory', history);

const trend = history.map((item) => ({
    time: item.time,
    oee: fixed(item.oee),
    quality: fixed(item.quality),
    performance: fixed(item.performance),
    availability: fixed(item.availability),
    error: fixed(item.error),
    oeeWidth: Math.max(6, Math.min(100, Math.round(item.oee))),
    qualityWidth: Math.max(6, Math.min(100, Math.round(item.quality))),
    performanceWidth: Math.max(6, Math.min(100, Math.round(item.performance)))
}));

let focus = [];
if (quality < 85) {
    focus.push('Kalite kritik seviyede. Hurda ve yeniden isleme akisina oncelik verin.');
} else if (quality < 92) {
    focus.push('Kalite uyari bandinda. Renk bazli kayip dagilimini yakin izleyin.');
} else {
    focus.push('Kalite seviyesi stabil. Mevcut ayar ve tempo korunabilir.');
}

if (isStopped) {
    focus.push('Aktif durus nedeni: ' + (faultState.reason || 'Bilinmiyor') + '.');
} else {
    focus.push('Plansiz durus gorunmuyor. OEE trendini vardiya boyunca takip edin.');
}

focus.push('En yuksek kayip orani ' + biggestLossColor.name + ' urun grubunda.');
focus = focus.slice(0, 3);

const oeeTone = oee >= 75 ? 'good' : (oee >= 60 ? 'warn' : 'bad');
const qualityTone = quality >= 92 ? 'good' : (quality >= 85 ? 'warn' : 'bad');
const stopTone = isStopped ? 'bad' : 'good';

msg.payload = {
    updatedAt: stamp(now),
    rawLine: line,
    header: {
        title: 'Konveyor OEE Kontrol Merkezi',
        subtitle: 'Ayni veri akisini koruyan ikinci dashboard tabi',
        lineState,
        stateSummary,
        tone: stopTone
    },
    kpis: [
        {
            label: 'Kullanilabilirlik',
            value: fixed(availability) + '%',
            tone: availability >= 90 ? 'good' : (availability >= 75 ? 'warn' : 'bad')
        },
        {
            label: 'Performans',
            value: fixed(performance) + '%',
            tone: performance >= 90 ? 'good' : (performance >= 75 ? 'warn' : 'bad')
        },
        {
            label: 'Kalite',
            value: fixed(quality) + '%',
            tone: qualityTone
        },
        {
            label: 'OEE',
            value: fixed(oee) + '%',
            tone: oeeTone,
            featured: true
        }
    ],
    production: [
        { label: 'Toplam urun', value: totalProduct, tone: 'neutral' },
        { label: 'Saglam urun', value: goodProduct, tone: 'good' },
        { label: 'Hurda', value: scrapTotal, tone: 'bad' },
        { label: 'Yeniden isleme', value: reworkTotal, tone: 'warn' }
    ],
    downtime: {
        planned: '0 aktif kayit',
        unplanned: isStopped ? '1 aktif kayit' : '0 aktif kayit',
        total: isStopped ? '1 aktif kayit' : '0 aktif kayit',
        reason: faultState.reason || 'Bilinmiyor',
        status: faultState.status || 'Yok'
    },
    targets: {
        ideal: totalProduct,
        actual: totalProduct,
        gap: 0,
        errorRate: fixed(errorRate) + '%',
        totalLoss: totalLoss
    },
    colors: colorCards,
    insights: [
        {
            label: 'Kalite alarmi',
            value: quality < 85 ? 'Kritik' : (quality < 92 ? 'Uyari' : 'Normal'),
            tone: qualityTone
        },
        {
            label: 'Durus durumu',
            value: isStopped ? 'Mudahale gerekli' : 'Hat aktif',
            tone: stopTone
        },
        {
            label: 'Oncelikli renk',
            value: biggestLossColor.name,
            tone: 'warn'
        },
        {
            label: 'En iyi kalite',
            value: bestQualityColor.name,
            tone: 'good'
        }
    ],
    trend,
    focus
};

return msg;
